//! Classify Azul C API functions from the embedded api.json.
//!
//! Each function in the API is classified into one of:
//! - **Framework**: Needed in azul-mini.wasm (DOM, layout, CSS, hit-testing)
//! - **ServerEntryPoint**: Excluded from WASM (AzApp_run, event loop)
//! - **ReplaceWithDomPatcher**: GPU/display-list fns replaced with setStyle() emitters
//!
//! The api.json is embedded as brotli-compressed bytes (generated by `azul-doc codegen all`)
//! and decompressed + parsed on first call. This adds ~120KB to the binary instead of ~3.7MB.

/// Brotli-compressed, minified api.json (generated by `azul-doc codegen all`).
/// ~120KB compressed from ~3.7MB raw. Decompressed on first call to `classify_api_functions()`.
static API_JSON_BR: &[u8] = include_bytes!(concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/../target/codegen/api.json.br"
));

/// How a C API function should be treated when generating WASM.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FnClass {
    /// Framework fn needed in WASM (AzDom_addChild, AzRefAny_clone, ...)
    Framework,
    /// Server entry point — NOT included in WASM (AzApp_run, etc.)
    ServerEntryPoint,
    /// Display list / GPU path — replaced with setStyle() emitters
    ReplaceWithDomPatcher,
}

/// Result of classifying all API functions.
#[derive(Debug)]
pub struct ApiClassification {
    pub functions: Vec<(String, FnClass)>,
}

impl ApiClassification {
    pub fn total(&self) -> usize {
        self.functions.len()
    }

    pub fn framework_count(&self) -> usize {
        self.functions.iter().filter(|(_, c)| *c == FnClass::Framework).count()
    }

    pub fn excluded_count(&self) -> usize {
        self.functions.iter().filter(|(_, c)| *c != FnClass::Framework).count()
    }
}

/// Classify all API functions by decompressing and parsing the embedded api.json.
///
/// Each function name is classified based on its prefix:
/// - `AzApp_run` → ServerEntryPoint
/// - `AzDisplayList_*`, `AzGl_*` → ReplaceWithDomPatcher
/// - Everything else → Framework
pub fn classify_api_functions() -> ApiClassification {
    // Decompress brotli
    let mut json_bytes = Vec::new();
    brotli_decompressor::BrotliDecompress(
        &mut &API_JSON_BR[..],
        &mut json_bytes,
    ).expect("Failed to decompress embedded api.json");

    let json_str = core::str::from_utf8(&json_bytes)
        .expect("Decompressed api.json is not valid UTF-8");

    // Parse the JSON to extract function names.
    // The api.json structure has a top-level object with a "classes" array,
    // each class has "constructors", "methods", "static_methods" etc.
    // The C function name is constructed as Az{ClassName}_{methodName}.
    // We use serde_json::Value for simplicity.
    let parsed: serde_json::Value = serde_json::from_str(json_str)
        .expect("Failed to parse decompressed api.json");

    let mut functions = Vec::new();

    if let Some(classes) = parsed.get("classes").and_then(|c| c.as_object()) {
        for (class_name, class_def) in classes {
            // Collect function names from each section
            let sections = &[
                "constructors", "methods", "static_methods",
                "trait_impls",
            ];
            for section in sections {
                if let Some(fns) = class_def.get(*section).and_then(|f| f.as_object()) {
                    for (fn_name, _) in fns {
                        let c_name = format!("Az{}_{}", class_name, fn_name);
                        let class = classify_fn(&c_name);
                        functions.push((c_name, class));
                    }
                }
            }
        }
    }

    ApiClassification { functions }
}

fn classify_fn(name: &str) -> FnClass {
    match name {
        "AzApp_run" => FnClass::ServerEntryPoint,
        n if n.starts_with("AzDisplayList_") => FnClass::ReplaceWithDomPatcher,
        n if n.starts_with("AzGl_") => FnClass::ReplaceWithDomPatcher,
        _ => FnClass::Framework,
    }
}
